#include <string>
#include <iostream>
#include <regex>

std::string markdownToHtml(const std::string& markdown) {
    std::string html = "";

    // Regular expression pattern to match markdown text
    std::regex pattern("(^[*#]+)(.*)([*#]+$)");

    // Loop through each match found by the regular expression pattern
    for (std::sregex_iterator it(markdown.begin(), markdown.end(), pattern);
         it!= std::sregex_iterator(); it++) {

        // Get the matched text
        std::string match = (*it)[0];

        // Check if the matched text is a header
        if (match.substr(0, 1) == "#") {
            // Append the opening HTML tag for the header level
            html += "<h" + match.substr(0, 1) + ">";
        }
        else {
            // Append the opening HTML tag for a paragraph
            html += "<p>";
        }

        // Append the text following the header level or paragraph tag
        html += (*it)[2];

        // Check if the matched text is a header
        if (match.substr(match.length() - 1, 1) == "#") {
            // Append the closing HTML tag for the header level
            html += "</h" + match.substr(match.length() - 1, 1) + ">";
        }
        else {
            // Append the closing HTML tag for a paragraph
            html += "</p>";
        }
    }

    return html;
}

int main() {
    std::string markdown = "This is a **bold** text. This is also an *italic* text. This is a #header 1, and this is a #header 2.";
    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;
    return 0;
}
```
